### Display Booking Information After Successful Booking

Source: https://github.com/calcom/cal.com/blob/main/docs/platform/guides/booking-redirects.mdx

This snippet demonstrates how to display booking details on a custom page after a successful booking. It uses the `useBooking` hook from `@calcom/atoms` to fetch booking data and handles both single bookings and recurring bookings. The booking UID is extracted from the URL parameters.

```javascript
import { useBooking } from "@calcom/atoms";
import { useRouter } from "next/router";

export default function Bookings(props: { calUsername: string; calEmail: string }) {
    const router = useRouter();

    const { isLoading, data: booking, refetch } = useBooking((router.query.bookingUid as string) ?? "");

    return (
        <>
          {!Array.isArray(booking) ? (
              <p>{booking.title}</p>
          ) : (
              booking.map((recurrence) => <p key={recurrence.id}>{recurrence.title}</p>)
          )}
        </>
    )
};
```

