### Cancel Booking Mutation with useCancelBooking Hook

Source: https://github.com/calcom/cal.com/blob/main/docs/platform/guides/booking-redirects.mdx

This snippet demonstrates how to implement a cancellation feature using the `useCancelBooking` hook from `@calcom/atoms`. It includes a mutation to cancel a booking and a `refetch` function to update the UI upon successful cancellation. The `useBooking` hook is used to retrieve booking details to obtain the booking ID.

```javascript
import { useBooking, useCancelBooking } from "@calcom/atoms";

...
const { isLoading, data: booking, refetch } = useBooking((router.query.bookingUid as string) ?? "");
const { mutate: cancelBooking } = useCancelBooking({
    onSuccess: () => {
      refetch();
    },
  });
...
   return !Array.isArray(booking) ? (
    <button
      className="underline"
      onClick={() => {
        cancelBooking({
          id: booking.id,
          cancellationReason: "User request",
        });
      }}
    >
      Cancel
    </button>
  ) : (
    <>
      {booking.map((recurrence) => (
        <button
          key={recurrence.id}
          className="underline"
          onClick={() => {
            cancelBooking({
              id: recurrence.id,
              cancellationReason: "User request",
            });
          }}
        >
          Cancel
        </button>
      ))}
    </>
  );

```

